+import type { OpenClawConfig } from "../config/config.js";
+
+export function applyOnboardingLocalWorkspaceConfig(
+  baseConfig: OpenClawConfig,
+  workspaceDir: string,
+): OpenClawConfig {
+  return {
+    ...baseConfig,
+    agents: {
+      ...baseConfig.agents,
+      defaults: {
+        ...baseConfig.agents?.defaults,
+        workspace: workspaceDir,
+      },
+    },
+    gateway: {
+      ...baseConfig.gateway,
+      mode: "local",
+    },
+  };
+}

